```package com.example.nativetestrepro

import androidx.appcompat.app.AppCompatActivity
import android.os.Bundle
import android.text.Editable
import android.text.TextWatcher
import android.widget.EditText

class MainActivity : AppCompatActivity() {

    private lateinit var editText: EditText
    // A flag to prevent infinite loops when we programmatically change the text.
    private var isFormatting = false

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_main)

        editText = findViewById(R.id.edit_text_capitalize)

        editText.addTextChangedListener(object : TextWatcher {
            override fun beforeTextChanged(s: CharSequence?, start: Int, count: Int, after: Int) {
                // No action needed here.
            }

            override fun onTextChanged(s: CharSequence?, start: Int, before: Int, count: Int) {
                // No action needed here.
            }

            override fun afterTextChanged(s: Editable?) {
                // Check the flag to prevent recursive calls.
                if (isFormatting || s == null) {
                    return
                }

                isFormatting = true

                val originalText = s.toString()
                val capitalizedText = originalText.capitalizeFirst()

                // Only update the text if it has actually changed.
                // This prevents the cursor from jumping unnecessarily.
                if (originalText != capitalizedText) {
                    // We set the text on the EditText itself and move the cursor to the end.
                    editText.setText(capitalizedText)
                    editText.setSelection(capitalizedText.length)
                }

                isFormatting = false
            }
        })
    }

    /**
     * Capitalizes the first letter of a given string.
     * This is an extension function for the String class.
     * @return The capitalized string, or the original string if it's empty.
     */
    private fun String.capitalizeFirst(): String {
        if (this.isEmpty()) {
            return this
        }
        // Return the first character as uppercase, followed by the rest of the string.
        return this.substring(0, 1).toUpperCase() + this.substring(1)
    }
}
